        <!-- Failing Entities -->\n        <div class=\"bg-white rounded-xl shadow-sm border border-gray-200 p-6 mb-8\">\n            <h2 class=\"text-lg font-semibold text-gray-900 mb-4\">Failing Entities ({{ $test->activeFailures()->count() }} unresolved)</h2>\n            @if($test->activeFailures()->count() > 0)\n                <div class=\"space-y-3\">\n                    @foreach($test->activeFailures() as $failure)\n                        <div class=\"border border-gray-200 rounded-lg p-4 bg-red-50\">\n                            <div class=\"flex items-start justify-between\">\n                                <div class=\"flex-1\">\n                                    <div class=\"font-medium text-gray-900 mb-1\">{{ $failure->failing_entity_description }}</div>\n                                    <div class=\"text-sm text-gray-600\">\n                                        Detected: {{ $failure->detected_at->format('M d, Y g:i A') }}\n                                    </div>\n                                </div>\n                                <span class=\"inline-flex px-2 py-1 text-xs font-semibold rounded-full bg-red-100 text-red-800\">\n                                    Unresolved\n                                </span>\n                            </div>\n                        </div>\n                    @endforeach\n                </div>\n            @else\n                <div class=\"text-center py-8\">\n                    <svg class=\"mx-auto h-12 w-12 text-gray-400\" fill=\"none\" stroke=\"currentColor\" viewBox=\"0 0 24 24\">\n                        <path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\" d=\"M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z\"/>\n                    </svg>\n                    <h3 class=\"mt-2 text-sm font-medium text-gray-900\">No unresolved failing entities</h3>\n                    <p class=\"mt-1 text-sm text-gray-500\">All tests have been resolved.</p>\n                </div>\